const payload = $json.body ?? $json;
const detailLevel = String(payload.detail_level ?? payload.detailLevel ?? 'brief').toLowerCase();
const messageId = String(payload.message_id ?? payload.messageId ?? '').trim();
const threadId = String(payload.thread_id ?? payload.threadId ?? '').trim();
const sender = String(payload.sender ?? '').trim();
const subject = String(payload.subject ?? '').trim();
const searchQuery = String(payload.search_query ?? payload.searchQuery ?? '').trim();

let query = searchQuery;
if (!query && subject) {
  query = `subject:"${subject}" newer_than:30d`;
}
if (!query && sender) {
  query = `from:${sender} newer_than:30d`;
}
if (!query) {
  query = 'newer_than:30d';
}

return [{
  json: {
    detail_level: detailLevel === 'full' ? 'full' : 'brief',
    message_id: messageId,
    thread_id: threadId,
    sender,
    subject,
    search_query: query,
  },
}];

const request = $('Normalize Detail Request').first().json;
const candidates = $input.all().map((item) => item.json).filter((mail) => mail && (mail.id || mail.payload));

if (!candidates.length) {
  return [{ json: {
    action: 'gmail-detail',
    found: false,
    reply: '요청한 조건에 맞는 메일을 찾지 못했습니다. 제목이나 발신자, 조회 범위를 더 구체적으로 알려주세요.'
  }}];
}

const readHeader = (headers, key) => {
  if (!Array.isArray(headers)) return '';
  const matched = headers.find((header) => String(header.name || '').toLowerCase() === key.toLowerCase());
  return matched?.value || '';
};

const decodeBase64Url = (value) => {
  if (!value) return '';
  try {
    const normalized = String(value).replace(/-/g, '+').replace(/_/g, '/');
    const pad = normalized.length % 4;
    const padded = normalized + (pad ? '='.repeat(4 - pad) : '');
    return Buffer.from(padded, 'base64').toString('utf8');
  } catch (e) {
    return '';
  }
};

const extractTextPart = (part) => {
  if (!part || typeof part !== 'object') return '';
  if (part.mimeType === 'text/plain' && part.body?.data) {
    return decodeBase64Url(part.body.data);
  }
  if (Array.isArray(part.parts)) {
    for (const child of part.parts) {
      const extracted = extractTextPart(child);
      if (extracted) return extracted;
    }
  }
  return '';
};

const pick = (() => {
  if (request.message_id) {
    const matched = candidates.find((mail) => String(mail.id || '') === String(request.message_id));
    if (matched) return matched;
  }
  if (request.thread_id) {
    const matched = candidates.find((mail) => String(mail.threadId || '') === String(request.thread_id));
    if (matched) return matched;
  }
  return candidates[0];
})();

const headers = pick.payload?.headers || [];
const subject = pick.subject || readHeader(headers, 'Subject') || '(제목 없음)';
const sender = pick.from?.text || readHeader(headers, 'From') || '발신자 미상';
const to = readHeader(headers, 'To') || '';
const date = readHeader(headers, 'Date') || '';
const snippet = String(pick.snippet || '').trim();
const bodyText = extractTextPart(pick.payload || {});
const plainBody = bodyText ? bodyText.replace(/\s+/g, ' ').trim() : '';

const lines = [
  '📩 메일 상세 정보',
  `- 제목: ${subject}`,
  `- 보낸 사람: ${sender}`,
  date ? `- 날짜: ${date}` : null,
  to ? `- 받는 사람: ${to}` : null,
  `- 메시지 ID: ${pick.id || ''}`,
  `- 스레드 ID: ${pick.threadId || ''}`,
  snippet ? `- 미리보기: ${snippet}` : null,
].filter(Boolean);

if (request.detail_level === 'full' && plainBody) {
  const bodyPreview = plainBody.length > 1600 ? `${plainBody.slice(0, 1600)}...` : plainBody;
  lines.push('', '본문:', bodyPreview);
}

return [{ json: {
  action: 'gmail-detail',
  found: true,
  messageId: String(pick.id || ''),
  threadId: String(pick.threadId || ''),
  detailLevel: request.detail_level,
  reply: lines.join('\n'),
}}];
